import React from "react"
import { Link, graphql } from "gatsby"
import Bio from "../components/bio"
import Layout from "../components/layout"
import SEO from "../components/seo"

class BlogPostTemplate extends React.Component {
  componentDidMount() {
    if (typeof window !== "undefined") {
      const Valine = require("valine")
      new Valine({
        el: "#vcomments",
        appId: "j3u9skdrWTJv9cBT2jUupUIy-gzGzoHsz",
        appKey: "ez6rm3n4MHxTJbhX4bkYQrdB",
        avatar: "monsterid",
        placeholder: "说点什么...",
        meta: ["nick", "mail"],
        // 设置Bilibili表情包地址
        emojiCDN: "//i0.hdslb.com/bfs/emote/",
        visitor: true, // 阅读量统计
        enableQQ: true,
        // 表情title和图片映射
        emojiMaps: {
          tv_doge: "6ea59c827c414b4a2955fe79e0f6fd3dcd515e24.png",
          tv_亲亲: "a8111ad55953ef5e3be3327ef94eb4a39d535d06.png",
          tv_偷笑: "bb690d4107620f1c15cff29509db529a73aee261.png",
          tv_再见: "180129b8ea851044ce71caf55cc8ce44bd4a4fc8.png",
          tv_冷漠: "b9cbc755c2b3ee43be07ca13de84e5b699a3f101.png",
          tv_发怒: "34ba3cd204d5b05fec70ce08fa9fa0dd612409ff.png",
          tv_发财: "34db290afd2963723c6eb3c4560667db7253a21a.png",
          tv_可爱: "9e55fd9b500ac4b96613539f1ce2f9499e314ed9.png",
          tv_吐血: "09dd16a7aa59b77baa1155d47484409624470c77.png",
          tv_呆: "fe1179ebaa191569b0d31cecafe7a2cd1c951c9d.png",
          tv_呕吐: "9f996894a39e282ccf5e66856af49483f81870f3.png",
          tv_困: "241ee304e44c0af029adceb294399391e4737ef2.png",
          tv_坏笑: "1f0b87f731a671079842116e0991c91c2c88645a.png",
          tv_大佬: "093c1e2c490161aca397afc45573c877cdead616.png",
          tv_大哭: "23269aeb35f99daee28dda129676f6e9ea87934f.png",
          tv_委屈: "d04dba7b5465779e9755d2ab6f0a897b9b33bb77.png",
          tv_害羞: "a37683fb5642fa3ddfc7f4e5525fd13e42a2bdb1.png",
          tv_尴尬: "7cfa62dafc59798a3d3fb262d421eeeff166cfa4.png",
          tv_微笑: "70dc5c7b56f93eb61bddba11e28fb1d18fddcd4c.png",
          tv_思考: "90cf159733e558137ed20aa04d09964436f618a1.png",
          tv_惊吓: "0d15c7e2ee58e935adc6a7193ee042388adc22af.png",
        },
      })
    }
  }

  render() {
    const post = this.props.data.markdownRemark
    const siteTitle = this.props.data.site.siteMetadata.title
    const { previous, next } = this.props.pageContext

    return (
      <article>
        <Layout location={this.props.location} title={siteTitle}>
          <SEO
            title={post.frontmatter.title}
            description={post.frontmatter.description || post.excerpt}
          />
          <h1>{post.frontmatter.title}</h1>
          <p
            style={{
              // ...scale(-1 / 5),
              display: `block`,
            }}
          >
            {post.frontmatter.date}
          </p>
          <div dangerouslySetInnerHTML={{ __html: post.html }} />
          <hr
            style={{
              margin: "2rem 0",
            }}
          />
          <div
            id={post.fields.slug}
            className="leancloud_visitors"
            data-flag-title={post.frontmatter.title}
            style={{
              textAlign: "right",
              marginTop: -10,
            }}
          >
            <em className="post-meta-item-text">阅读量 </em>
            <i className="leancloud-visitors-count"></i>
          </div>
          <Bio />
          <ul
            style={{
              display: `flex`,
              flexWrap: `wrap`,
              justifyContent: `space-between`,
              listStyle: `none`,
              padding: 0,
            }}
          >
            <li>
              {previous && (
                <Link to={previous.fields.slug} rel="prev">
                  ← {previous.frontmatter.title}
                </Link>
              )}
            </li>
            <li>
              {next && (
                <Link to={next.fields.slug} rel="next">
                  {next.frontmatter.title} →
                </Link>
              )}
            </li>
          </ul>
          <div id="vcomments" className="blog-post-comments v" />
        </Layout>
      </article>
    )
  }
}

export default BlogPostTemplate

export const pageQuery = graphql`
  query BlogPostBySlug($slug: String!) {
    site {
      siteMetadata {
        title
        author
      }
    }
    markdownRemark(fields: { slug: { eq: $slug } }) {
      id
      excerpt(pruneLength: 160)
      html
      fields {
        slug
      }
      frontmatter {
        title
        date(formatString: "MMMM DD, YYYY")
        description
      }
    }
  }
`
